import type { CareerQuestion } from "./rrt-questions";

export const cardiacSonographerQuestionsBatch4: CareerQuestion[] = [
  { id: "cardecho-170", stem: "The simplified Bernoulli equation ΔP = 4V² assumes:", options: ["The proximal velocity is negligible (<1 m/s) and viscous losses are minimal", "Blood viscosity is the dominant factor", "Flow is always turbulent", "The proximal velocity is always greater than the distal velocity"], correctIndex: 0, rationale: "The full Bernoulli: ΔP = 4(V2² - V1²) + viscous friction + acceleration. When V1 <1 m/s, V1² is negligible. Viscous and acceleration terms are small in most clinical scenarios.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Bernoulli Equation" },
  { id: "cardecho-171", stem: "When should the expanded Bernoulli equation (ΔP = 4[V2² - V1²]) be used instead of the simplified version?", options: ["When proximal velocity (V1) exceeds 1.5 m/s, such as in LVOT obstruction or aortic subvalvular stenosis", "Always, regardless of proximal velocity", "Only for tricuspid regurgitation", "Only in pediatric patients"], correctIndex: 0, rationale: "When V1 >1.5 m/s (e.g., subvalvular membrane, HOCM), ignoring V1 overestimates the gradient. The expanded form accounts for significant proximal velocity contribution.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Bernoulli Equation" },
  { id: "cardecho-172", stem: "A peak aortic valve velocity of 5 m/s corresponds to a peak instantaneous gradient of:", options: ["100 mmHg", "50 mmHg", "25 mmHg", "200 mmHg"], correctIndex: 0, rationale: "ΔP = 4V² = 4 × 5² = 4 × 25 = 100 mmHg. This represents the peak instantaneous gradient, which is higher than the peak-to-peak gradient measured at catheterization.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Bernoulli Equation" },
  { id: "cardecho-173", stem: "The mean pressure gradient across a stenotic valve is calculated from:", options: ["The integral of instantaneous gradients over the entire flow period using the Doppler spectral envelope", "Peak velocity only", "Heart rate times peak velocity", "LVOT diameter squared"], correctIndex: 0, rationale: "Mean gradient is obtained by tracing the CW Doppler spectral envelope; the ultrasound machine integrates 4V² over the ejection period and divides by ejection time. It correlates better with catheterization gradients.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Bernoulli Equation" },
  { id: "cardecho-174", stem: "The continuity equation is based on the principle of:", options: ["Conservation of mass: flow through the LVOT equals flow through the aortic valve", "Conservation of energy only", "Laplace's law", "Poiseuille's law"], correctIndex: 0, rationale: "Conservation of mass: in the absence of shunts, flow (volume per unit time) is constant at any point along a tube. A_LVOT × VTI_LVOT = A_AV × VTI_AV.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Continuity Equation" },
  { id: "cardecho-175", stem: "Using the continuity equation, if LVOT diameter is 2.0 cm, LVOT VTI is 22 cm, and AV VTI is 88 cm, the aortic valve area is:", options: ["0.79 cm²", "1.5 cm²", "2.0 cm²", "3.14 cm²"], correctIndex: 0, rationale: "LVOT area = π × (2.0/2)² = 3.14 cm². AVA = (3.14 × 22) / 88 = 69.1 / 88 = 0.79 cm². This is consistent with severe AS (AVA <1.0 cm²).", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Continuity Equation" },
  { id: "cardecho-176", stem: "A 1-mm error in LVOT diameter measurement significantly affects AVA calculation because:", options: ["LVOT diameter is squared in the area formula, amplifying any measurement error", "LVOT diameter is added to VTI", "The error cancels out in the ratio", "It only affects heart rate calculations"], correctIndex: 0, rationale: "LVOT area = π(d/2)², so diameter is squared. A 1-mm error in a 2.0-cm LVOT changes area by ~10%, directly affecting AVA calculation. Careful measurement at the AV annulus in PLAX during mid-systole is essential.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Continuity Equation" },
  { id: "cardecho-177", stem: "The dimensionless velocity index (DVI) is calculated as:", options: ["LVOT VTI divided by AV VTI (or LVOT peak velocity / AV peak velocity)", "AV VTI times LVOT area", "Peak velocity squared", "Mean gradient divided by heart rate"], correctIndex: 0, rationale: "DVI = LVOT VTI / AV VTI. Normal DVI >0.50. DVI <0.25 indicates severe AS. DVI avoids LVOT diameter measurement, eliminating its error source. Essentially represents the fraction of the LVOT used by the AV.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Continuity Equation" },
  { id: "cardecho-178", stem: "Stroke volume by Doppler is calculated as:", options: ["LVOT cross-sectional area × LVOT VTI", "Peak velocity × ejection time", "Heart rate × LVOT diameter", "Mean gradient × valve area"], correctIndex: 0, rationale: "SV = CSA_LVOT × VTI_LVOT = π(d/2)² × VTI. Normal SV is 60-100 mL. This method assumes laminar flow and a circular LVOT cross-section.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-179", stem: "If LVOT diameter is 2.2 cm and LVOT VTI is 20 cm, the stroke volume is approximately:", options: ["76 mL", "44 mL", "120 mL", "200 mL"], correctIndex: 0, rationale: "CSA = π × (2.2/2)² = π × 1.21 = 3.80 cm². SV = 3.80 × 20 = 76 mL. This is within the normal range (60-100 mL).", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-180", stem: "Stroke volume index (SVI) is calculated by:", options: ["Dividing stroke volume by body surface area (BSA)", "Multiplying stroke volume by heart rate", "Dividing stroke volume by heart rate", "Multiplying stroke volume by BSA"], correctIndex: 0, rationale: "SVI = SV / BSA. Normal SVI is 33-47 mL/m². SVI <35 mL/m² indicates low-flow state, important in assessing low-flow, low-gradient aortic stenosis.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-181", stem: "Cardiac output by Doppler is:", options: ["Stroke volume multiplied by heart rate", "LVOT VTI divided by heart rate", "Peak velocity times LVOT area", "Mean gradient times valve area"], correctIndex: 0, rationale: "CO = SV × HR. Normal CO is 4-8 L/min. Cardiac index (CI) = CO/BSA. Normal CI is 2.5-4.0 L/min/m². CI <2.2 L/min/m² indicates reduced cardiac output.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Cardiac Output" },
  { id: "cardecho-182", stem: "If stroke volume is 70 mL and heart rate is 80 bpm, cardiac output is:", options: ["5.6 L/min", "8.75 L/min", "0.875 L/min", "56 L/min"], correctIndex: 0, rationale: "CO = 70 mL × 80 beats/min = 5600 mL/min = 5.6 L/min. This is within the normal range of 4-8 L/min.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Cardiac Output" },
  { id: "cardecho-183", stem: "Cardiac index (CI) is derived by:", options: ["Dividing cardiac output by body surface area", "Multiplying cardiac output by body weight", "Dividing cardiac output by heart rate", "Adding stroke volume to heart rate"], correctIndex: 0, rationale: "CI = CO / BSA. Indexing to BSA normalizes for body size. Normal CI: 2.5-4.0 L/min/m². CI <2.2 L/min/m² is considered severely reduced and may indicate cardiogenic shock.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Cardiac Output" },
  { id: "cardecho-184", stem: "The Gorlin formula for valve area calculation uses:", options: ["Flow across the valve divided by the product of a constant and the square root of the mean gradient", "Peak velocity squared", "LVOT diameter only", "IVC diameter and collapsibility"], correctIndex: 0, rationale: "Gorlin formula: AVA = CO / (SEP × HR × 44.3 × √mean gradient). It was the catheterization-era gold standard. The continuity equation is the Doppler equivalent and does not require invasive measurement.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-185", stem: "Mitral valve area by pressure half-time (PHT) is calculated as:", options: ["MVA = 220 / PHT", "MVA = PHT / 220", "MVA = 4 × PHT²", "MVA = PHT × heart rate"], correctIndex: 0, rationale: "MVA = 220/PHT. The empirical constant 220 was derived from correlation with catheterization data. PHT is the time for the peak E-wave gradient to halve. Severe MS: PHT >220 ms (MVA <1.0 cm²).", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Pressure Half-Time" },
  { id: "cardecho-186", stem: "A pressure half-time of 300 ms on the mitral inflow Doppler corresponds to a mitral valve area of:", options: ["0.73 cm²", "1.5 cm²", "2.2 cm²", "3.0 cm²"], correctIndex: 0, rationale: "MVA = 220/300 = 0.73 cm². This indicates severe MS (MVA <1.0 cm²). Normal MVA is 4-6 cm².", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Pressure Half-Time" },
  { id: "cardecho-187", stem: "Pressure half-time for aortic regurgitation severity is measured from:", options: ["The CW Doppler spectral envelope of the AR jet in the descending slope", "Mitral inflow E wave", "LVOT forward flow", "Tricuspid regurgitation jet"], correctIndex: 0, rationale: "AR PHT is measured from the CW Doppler of the AR jet deceleration slope. Severe AR: PHT <200 ms (rapid pressure equalization). Mild AR: PHT >500 ms.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Pressure Half-Time" },
  { id: "cardecho-188", stem: "A short AR pressure half-time (<200 ms) indicates:", options: ["Severe aortic regurgitation with rapid equalization of aortic and LV diastolic pressures", "Mild AR", "Normal valve function", "Aortic stenosis"], correctIndex: 0, rationale: "Short PHT reflects rapid decline in the aortic-LV diastolic pressure difference due to severe regurgitant volume. The LV diastolic pressure rises quickly, equalizing with the aorta.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Pressure Half-Time" },
  { id: "cardecho-189", stem: "Limitations of pressure half-time for MVA include inaccuracy in:", options: ["Patients with abnormal LV compliance, significant AR, or immediately after mitral valvuloplasty", "Normal sinus rhythm only", "High heart rates only", "Young patients only"], correctIndex: 0, rationale: "PHT is unreliable with altered LV compliance (e.g., diastolic dysfunction, AR), immediately post-valvuloplasty (LV compliance has not yet adapted), and with coexisting significant AR.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Pressure Half-Time" },
  { id: "cardecho-190", stem: "dP/dt of the left ventricle is measured from:", options: ["The CW Doppler mitral regurgitation jet, using the time interval between 1 m/s and 3 m/s", "Aortic valve forward flow", "Mitral inflow E wave", "LVOT VTI"], correctIndex: 0, rationale: "dP/dt = 32 mmHg / Δt (time from 1 to 3 m/s on the MR jet). Using Bernoulli: at 1 m/s ΔP=4 mmHg, at 3 m/s ΔP=36 mmHg. Difference = 32 mmHg. Normal dP/dt >1200 mmHg/s.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "dP/dt" },
  { id: "cardecho-191", stem: "A dP/dt value of less than 600 mmHg/s indicates:", options: ["Severely impaired LV contractility", "Normal systolic function", "Enhanced contractility", "Diastolic dysfunction only"], correctIndex: 0, rationale: "dP/dt <600 mmHg/s indicates severe LV systolic dysfunction. Normal dP/dt >1200 mmHg/s. It reflects the rate of LV pressure rise during isovolumic contraction and is a measure of contractility.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "dP/dt" },
  { id: "cardecho-192", stem: "The Qp/Qs ratio compares:", options: ["Pulmonary blood flow to systemic blood flow to quantify intracardiac shunts", "Left atrial to right atrial pressure", "Systolic to diastolic blood pressure", "LV to RV ejection fraction"], correctIndex: 0, rationale: "Qp/Qs = (RVOT area × RVOT VTI) / (LVOT area × LVOT VTI). Qp/Qs = 1 is normal (no shunt). Qp/Qs >1.5 indicates hemodynamically significant left-to-right shunt.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Qp/Qs" },
  { id: "cardecho-193", stem: "To calculate Qp/Qs by Doppler, measurements are needed at:", options: ["The RVOT (diameter and VTI) and the LVOT (diameter and VTI)", "Only the mitral valve", "Only the aortic valve", "The IVC and SVC"], correctIndex: 0, rationale: "Qp = RVOT CSA × RVOT VTI; Qs = LVOT CSA × LVOT VTI. Qp/Qs = (RVOT CSA × RVOT VTI) / (LVOT CSA × LVOT VTI). Assumes no valvular regurgitation at measurement sites.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Qp/Qs" },
  { id: "cardecho-194", stem: "A Qp/Qs ratio of 2.0 indicates:", options: ["Pulmonary blood flow is twice the systemic flow, consistent with a significant left-to-right shunt", "Normal flow ratio", "Right-to-left shunting", "Balanced bidirectional shunt"], correctIndex: 0, rationale: "Qp/Qs 2.0 means twice as much blood flows through the pulmonary circuit compared to systemic. This significant shunt (>1.5) typically warrants intervention to prevent pulmonary vascular disease.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Qp/Qs" },
  { id: "cardecho-195", stem: "The PISA (proximal isovelocity surface area) method relies on the principle that:", options: ["Flow converges as concentric hemispheres proximal to a regurgitant orifice, with velocity increasing as radius decreases", "Flow is laminar throughout the cardiac cycle", "Velocity is constant at all distances from the orifice", "Only CW Doppler is needed"], correctIndex: 0, rationale: "PISA uses the continuity principle: flow rate at the hemispheric shell = 2πr² × aliasing velocity = regurgitant flow rate. The hemisphere is visible on color Doppler at the Nyquist velocity.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-196", stem: "The PISA radius is measured:", options: ["From the aliasing boundary to the regurgitant orifice on the color Doppler image after adjusting the Nyquist limit", "From the apex of the ventricle to the base", "At the vena contracta", "At the narrowest point of the jet"], correctIndex: 0, rationale: "The PISA radius is measured at the first aliasing contour (color reversal) proximal to the orifice. The Nyquist limit should be shifted toward the flow to optimize the hemisphere size for accurate measurement.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-197", stem: "Using PISA, the effective regurgitant orifice area (EROA) for mitral regurgitation is calculated as:", options: ["EROA = (2πr² × Valiasing) / Vmax MR jet", "EROA = Vmax / (2πr²)", "EROA = πr² only", "EROA = 4V²"], correctIndex: 0, rationale: "Flow rate = 2πr² × Va (aliasing velocity). EROA = Flow rate / Vmax (peak MR velocity by CW). Severe MR: EROA ≥0.4 cm². Regurgitant volume = EROA × MR VTI.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-198", stem: "An EROA ≥0.4 cm² for mitral regurgitation indicates:", options: ["Severe MR", "Mild MR", "Moderate MR", "Normal valve function"], correctIndex: 0, rationale: "Severe primary MR criteria: EROA ≥0.4 cm², regurgitant volume ≥60 mL, regurgitant fraction ≥50%. For secondary (functional) MR, severe is defined at EROA ≥0.2 cm² per guidelines.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-199", stem: "The regurgitant volume using PISA is calculated as:", options: ["EROA × VTI of the regurgitant jet (MR VTI from CW Doppler)", "Peak velocity squared", "LVOT VTI × heart rate", "E/A ratio × LA volume"], correctIndex: 0, rationale: "Regurgitant volume = EROA × MR VTI. This provides the total volume of blood regurgitating per beat. Severe MR: regurgitant volume ≥60 mL for primary MR.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-200", stem: "Regurgitant fraction is calculated as:", options: ["Regurgitant volume divided by total stroke volume × 100%", "Regurgitant volume times heart rate", "EROA divided by valve area", "Peak velocity divided by mean velocity"], correctIndex: 0, rationale: "Regurgitant fraction = (Regurgitant volume / Total LV stroke volume) × 100%. Total SV can be measured by LV volumetric method. Severe MR: RF ≥50%.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-201", stem: "The E/e' ratio estimates:", options: ["Left ventricular filling pressure", "Cardiac output", "Pulmonary vascular resistance", "Aortic valve gradient"], correctIndex: 0, rationale: "E/e' correlates with LV filling pressures (PCWP/LVEDP). E = mitral inflow E velocity; e' = tissue Doppler early diastolic velocity at the mitral annulus. E/e' >14 suggests elevated filling pressures.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-202", stem: "An E/e' ratio greater than 14 suggests:", options: ["Elevated LV filling pressures", "Normal diastolic function", "Reduced cardiac output", "Aortic stenosis"], correctIndex: 0, rationale: "E/e' >14 (using average of septal and lateral e') indicates elevated filling pressures (PCWP >15 mmHg). E/e' <8 suggests normal pressures. Values 8-14 are indeterminate.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-203", stem: "The septal e' velocity is normally:", options: ["≥7 cm/s", "≥15 cm/s", "<3 cm/s", "≥25 cm/s"], correctIndex: 0, rationale: "Normal septal e' ≥7 cm/s and lateral e' ≥10 cm/s. Reduced e' indicates impaired myocardial relaxation. The average of septal and lateral e' is used for the E/e' ratio.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-204", stem: "In the assessment of diastolic dysfunction, Grade I (impaired relaxation) is characterized by:", options: ["E/A ratio <0.8, prolonged DT >200 ms, normal or low E/e'", "E/A ratio >2.0 with short DT", "E/A ratio 0.8-1.5 with elevated E/e'", "Normal E/A ratio in a young patient"], correctIndex: 0, rationale: "Grade I (impaired relaxation): E/A <0.8, DT >200 ms, e' reduced, E/e' <8-10. This represents the earliest stage of diastolic dysfunction with normal filling pressures.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-205", stem: "Grade III diastolic dysfunction (restrictive filling) is identified by:", options: ["E/A ratio ≥2.0, short deceleration time <150 ms, elevated E/e' >14", "E/A ratio <0.8", "Normal E/A with normal DT", "E/e' ratio <8"], correctIndex: 0, rationale: "Grade III (restrictive): E/A ≥2, DT <150 ms, E/e' >14, increased LA volume. If the pattern reverses with Valsalva, it is Grade III (reversible). If not, Grade IV (fixed/irreversible).", difficulty: 3, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-206", stem: "Pseudonormal filling pattern (Grade II diastolic dysfunction) can be unmasked by:", options: ["Valsalva maneuver, which decreases preload and reveals the underlying impaired relaxation pattern", "Increasing heart rate", "IV fluid bolus", "Deep inspiration"], correctIndex: 0, rationale: "Valsalva reduces preload, unmasking the underlying impaired relaxation (E/A reversal). Pseudonormal appears normal on mitral inflow but tissue Doppler shows reduced e' and elevated E/e'.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-207", stem: "Pulmonary artery systolic pressure (PASP) is estimated using:", options: ["4 × (TR peak velocity)² + estimated right atrial pressure", "Mitral inflow E velocity", "LVOT peak velocity", "Aortic valve mean gradient"], correctIndex: 0, rationale: "PASP = 4V²_TR + RAP. The TR jet velocity reflects the RV-RA systolic pressure gradient. Adding estimated RAP (from IVC assessment) gives PASP. PASP = RV systolic pressure in the absence of pulmonic stenosis.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-208", stem: "If TR peak velocity is 3.5 m/s and estimated RAP is 10 mmHg, PASP is:", options: ["59 mmHg", "49 mmHg", "24.5 mmHg", "80 mmHg"], correctIndex: 0, rationale: "PASP = 4 × (3.5)² + 10 = 4 × 12.25 + 10 = 49 + 10 = 59 mmHg. This indicates moderate pulmonary hypertension (normal PASP <35-40 mmHg).", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-209", stem: "Mean pulmonary artery pressure (mPAP) can be estimated by:", options: ["0.61 × PASP + 2 mmHg, or from the peak PR velocity using 4V²_early PR + RAP", "PASP / 2", "PASP + RAP", "Heart rate × stroke volume"], correctIndex: 0, rationale: "mPAP = 0.61 × PASP + 2 (Chemla formula). Alternatively, mPAP = 4 × (early PR velocity)² + RAP. Pulmonary hypertension defined as mPAP >20 mmHg by current guidelines.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-210", stem: "Pulmonary artery diastolic pressure (PADP) is estimated from:", options: ["End-diastolic PR velocity using 4V²_end-diastolic PR + RAP", "TR peak velocity", "Mitral E/A ratio", "LVOT VTI"], correctIndex: 0, rationale: "PADP = 4 × (end-diastolic PR velocity)² + RAP. End-diastolic PR velocity reflects the PA-RV diastolic pressure difference. Elevated PADP in the absence of pulmonary disease suggests elevated PCWP.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-211", stem: "IVC diameter >2.1 cm with less than 50% inspiratory collapse estimates RAP at:", options: ["15 mmHg", "3 mmHg", "0 mmHg", "25 mmHg"], correctIndex: 0, rationale: "Dilated IVC (>2.1 cm) with <50% sniff collapse = RAP 10-20 mmHg (use 15). Normal IVC (<2.1 cm) with >50% collapse = RAP 0-5 mmHg (use 3). Intermediate = 8 mmHg.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-212", stem: "Pulmonary vascular resistance (PVR) can be estimated echocardiographically by:", options: ["TR peak velocity / RVOT VTI × 10 (Wood units)", "PASP / cardiac output directly", "E/e' ratio", "LVOT diameter squared"], correctIndex: 0, rationale: "PVR ≈ (TRV / VTI_RVOT) × 10 + 0.16. TRV/VTI_RVOT >0.275 suggests PVR >3 Wood units. This non-invasive estimate correlates with catheterization-derived PVR.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Vascular Resistance" },
  { id: "cardecho-213", stem: "Systemic vascular resistance (SVR) relates to:", options: ["(Mean arterial pressure - CVP) / cardiac output × 80 dynes·sec·cm⁻⁵", "PASP - PCWP only", "Heart rate times stroke volume", "E/e' ratio × BSA"], correctIndex: 0, rationale: "SVR = (MAP - CVP) / CO × 80. Normal SVR: 800-1200 dynes·sec·cm⁻⁵. Echocardiography provides CO; MAP and CVP from clinical assessment or catheterization.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Vascular Resistance" },
  { id: "cardecho-214", stem: "The velocity-time integral (VTI) represents:", options: ["The area under the Doppler spectral envelope, equivalent to the stroke distance", "Peak velocity only", "Mean velocity only", "Acceleration time"], correctIndex: 0, rationale: "VTI (cm) is the integral of velocity over time, representing the distance a column of blood travels per beat. Multiplied by cross-sectional area, it yields stroke volume.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-215", stem: "An LVOT VTI less than 18 cm suggests:", options: ["Reduced stroke volume and low cardiac output", "Normal cardiac output", "Aortic regurgitation", "Elevated filling pressures"], correctIndex: 0, rationale: "LVOT VTI <18-20 cm suggests low stroke volume. Combined with LVOT area, formal SV can be calculated. Low LVOT VTI is used as a surrogate for low CO in clinical practice.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-216", stem: "Mitral valve area by planimetry is measured from:", options: ["The parasternal short-axis view at the mitral valve tips during diastolic opening", "The apical four-chamber view", "The suprasternal view", "M-mode of the mitral valve"], correctIndex: 0, rationale: "Planimetry traces the inner edge of the mitral orifice at the leaflet tips in PSAX during early diastole. This method is independent of flow and compliance, making it the reference 2D method for MVA.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-217", stem: "Severe mitral stenosis is defined as MVA:", options: ["<1.0 cm²", "<2.0 cm²", "<3.0 cm²", "<4.0 cm²"], correctIndex: 0, rationale: "Severe MS: MVA <1.0 cm². Moderate: 1.0-1.5 cm². Mild: 1.5-2.0 cm². Normal MVA: 4-6 cm². Mean gradient >10 mmHg and PASP >50 mmHg also indicate severe MS.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-218", stem: "The continuity equation can also be used to calculate mitral valve area by:", options: ["Comparing flow at the LVOT with flow at the mitral valve: MVA = (LVOT area × LVOT VTI) / MV VTI", "Using the Bernoulli equation alone", "Multiplying E velocity by A velocity", "Dividing heart rate by mean gradient"], correctIndex: 0, rationale: "In the absence of MR or AR, flow through the MV equals flow through the LVOT. MVA = (LVOT CSA × LVOT VTI) / MV VTI. This provides an alternative when planimetry is suboptimal.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-219", stem: "The deceleration time (DT) of the mitral E wave in normal subjects is:", options: ["160-220 ms", "50-80 ms", "400-600 ms", ">800 ms"], correctIndex: 0, rationale: "Normal DT is 160-220 ms. Prolonged DT (>220 ms) suggests impaired relaxation (Grade I DD). Short DT (<150 ms) suggests restrictive physiology (Grade III DD).", difficulty: 2, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-220", stem: "The isovolumic relaxation time (IVRT) is measured from:", options: ["Aortic valve closure to mitral valve opening", "Mitral valve closure to aortic valve opening", "End of E wave to beginning of A wave", "Peak of R wave to start of T wave"], correctIndex: 0, rationale: "IVRT is the interval from AVC to MVO. Normal IVRT: 70-90 ms. Prolonged IVRT (>100 ms) = impaired relaxation. Shortened IVRT (<60 ms) = elevated LA pressure or severe AI.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-221", stem: "Pulmonary vein flow in normal subjects shows:", options: ["Systolic dominant flow (S > D) with a small atrial reversal (Ar) wave", "Diastolic dominant flow with large Ar wave", "Absent systolic flow", "Retrograde systolic flow"], correctIndex: 0, rationale: "Normal pulmonary vein flow: S wave > D wave, small Ar wave (<35 cm/s, duration <atrial contraction duration). As filling pressures rise, D becomes dominant and Ar increases.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-222", stem: "An Ar wave duration exceeding mitral A wave duration by >30 ms on pulmonary vein Doppler suggests:", options: ["Elevated left ventricular end-diastolic pressure", "Normal diastolic function", "Mitral stenosis", "Tricuspid regurgitation"], correctIndex: 0, rationale: "Ar duration - A duration >30 ms indicates elevated LVEDP. The prolonged Ar reflects the atrial pressure wave bouncing back into the pulmonary veins when the non-compliant LV resists filling.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-223", stem: "The acceleration time (AT) of RVOT Doppler flow is used to assess:", options: ["Pulmonary hypertension severity; shortened AT (<105 ms) suggests elevated pulmonary pressures", "Aortic valve stenosis", "Mitral valve area", "Left ventricular contractility"], correctIndex: 0, rationale: "RVOT acceleration time (time from onset to peak velocity) shortens with increasing pulmonary pressures. AT <105 ms suggests PH. Mid-systolic notching of the RVOT Doppler also indicates PH.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-224", stem: "Mid-systolic notching of the RVOT Doppler envelope is associated with:", options: ["Elevated pulmonary vascular resistance and precapillary pulmonary hypertension", "Normal pulmonary pressures", "Aortic stenosis", "Mitral regurgitation"], correctIndex: 0, rationale: "Mid-systolic notching (deceleration followed by re-acceleration) reflects high pulmonary impedance causing early reflection of the pressure wave. It is specific for precapillary PH (elevated PVR).", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-225", stem: "The ratio of RVOT acceleration time to RV ejection time (AT/ET) in pulmonary hypertension is:", options: ["Decreased (<0.35) compared to normal (>0.40)", "Increased (>0.60)", "Always 1.0", "Not affected by pulmonary pressure"], correctIndex: 0, rationale: "AT/ET decreases in PH because AT shortens disproportionately to ET. AT/ET <0.35 suggests significant PH. This ratio is less heart rate dependent than AT alone.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-226", stem: "Hepatic vein Doppler in severe tricuspid regurgitation shows:", options: ["Systolic flow reversal", "Increased systolic forward flow", "Normal biphasic flow", "Absent diastolic flow"], correctIndex: 0, rationale: "Severe TR causes systolic reversal in hepatic vein flow (blood is pushed backward into the hepatic veins during ventricular systole). This is an important supportive sign of severe TR.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-227", stem: "The ratio of systolic to diastolic (S/D) pulmonary vein flow reversal helps differentiate:", options: ["Elevated left atrial pressure (D-dominant) from normal (S-dominant)", "Right ventricular function", "Pulmonic stenosis severity", "TR severity"], correctIndex: 0, rationale: "Normal: S/D >1. With elevated LA pressure, the S wave decreases and D wave increases (S/D <1). Blunted or reversed S wave strongly suggests elevated LA pressure (>15 mmHg).", difficulty: 3, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-228", stem: "In a patient with atrial fibrillation, diastolic function assessment relies on:", options: ["E/e' ratio, deceleration time, and pulmonary vein Doppler since the A wave is absent", "E/A ratio alone", "A wave velocity", "Mitral A duration"], correctIndex: 0, rationale: "In AF, the A wave is absent, so E/A ratio cannot be used. E/e' ratio, DT, IVRT, pulmonary vein flow patterns, and LA volume index are used to assess diastolic function.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-229", stem: "The transmitral E wave velocity is primarily influenced by:", options: ["The LA-LV pressure gradient during early diastole", "Heart rate only", "RV function", "Aortic valve gradient"], correctIndex: 0, rationale: "The E wave reflects the pressure gradient between LA and LV during early diastolic filling. It is influenced by LA pressure, LV relaxation rate, LV compliance, and heart rate.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-230", stem: "In constrictive pericarditis, the annulus paradoxus refers to:", options: ["E/e' ratio suggesting normal filling pressures despite clinically elevated pressures, because e' is preserved or elevated", "Normal E/e' ratio with normal filling pressures", "Very high E/e' with low filling pressures", "Absent e' signal"], correctIndex: 0, rationale: "In constriction, the medial e' velocity is paradoxically preserved or increased (annulus paradoxus) because pericardial restriction shifts motion medially. E/e' may be misleadingly low despite elevated pressures.", difficulty: 5, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-231", stem: "The velocity ratio (LVOT VTI / AV VTI) is also known as:", options: ["Dimensionless index or dimensionless velocity index (DVI)", "Pressure half-time ratio", "Regurgitant fraction", "Cardiac index"], correctIndex: 0, rationale: "The dimensionless index (DI or DVI) = LVOT VTI / AV VTI. It is the ratio of flow velocities proximal and distal to the AV. DVI <0.25 = severe AS. It avoids LVOT diameter measurement errors.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Continuity Equation" },
  { id: "cardecho-232", stem: "Energy loss index accounts for:", options: ["Pressure recovery distal to a stenotic aortic valve, which is more significant in small aortas", "Heart rate variability", "Patient body weight", "Transducer frequency"], correctIndex: 0, rationale: "Energy loss index (ELI) corrects AVA for pressure recovery that occurs in small ascending aortas. Pressure recovery can cause Doppler to overestimate AS severity. ELI = (AVA × Aa) / (Aa - AVA), indexed to BSA.", difficulty: 5, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-233", stem: "The acceleration time of the aortic valve Doppler signal is used to assess:", options: ["The severity of aortic stenosis; prolonged AT suggests significant obstruction", "Mitral valve area", "Pulmonary pressures", "Diastolic function"], correctIndex: 0, rationale: "AV acceleration time (time to peak velocity) is prolonged in AS. AT >100 ms or AT/ET >0.36 suggests severe AS. A rounded, late-peaking spectral envelope further supports severity.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-234", stem: "Projected AVA at normal flow rate corrects for:", options: ["Flow dependence of valve area in low-flow states, predicting AVA at a standardized flow of 250 mL/s", "High-output states only", "Heart rhythm", "Patient position"], correctIndex: 0, rationale: "Projected AVA estimates what the AVA would be at a normal flow rate (250 mL/s), helping distinguish true severe AS from pseudo-severe AS in low-flow states without dobutamine stress.", difficulty: 5, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-235", stem: "The Doppler velocity index (DVI) value of 0.20 indicates:", options: ["Severe aortic stenosis (DVI <0.25 is severe)", "Normal aortic valve function", "Mild aortic stenosis", "Aortic regurgitation"], correctIndex: 0, rationale: "DVI <0.25 = severe AS. DVI 0.25-0.50 = moderate AS. DVI >0.50 = mild or no AS. A DVI of 0.20 means only 20% of the LVOT cross-section is effectively used by the stenotic valve.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Continuity Equation" },
  { id: "cardecho-236", stem: "Stroke work is estimated echocardiographically by:", options: ["Stroke volume × systolic blood pressure (as a simplified surrogate)", "Heart rate × ejection time", "E/A ratio × DT", "LVEF × heart rate"], correctIndex: 0, rationale: "Stroke work ≈ SV × mean arterial pressure. Echocardiographic SV combined with cuff BP provides a non-invasive estimate. Valvular heart index uses stroke work to assess severity in paradoxical AS.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-237", stem: "In severe mitral regurgitation, the volumetric method calculates regurgitant volume as:", options: ["Total LV stroke volume (by Simpson's) minus forward stroke volume (by LVOT Doppler)", "Peak MR velocity × 4", "E/e' × BSA", "Heart rate × LVOT VTI"], correctIndex: 0, rationale: "Regurgitant volume = Total SV (Simpson's biplane EDV - ESV) - Forward SV (LVOT CSA × LVOT VTI). The difference represents the volume regurgitating through the mitral valve each beat.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-238", stem: "The vena contracta width for mitral regurgitation is measured:", options: ["At the narrowest portion of the regurgitant jet just distal to the orifice, perpendicular to the jet axis", "At the widest portion of the jet in the LA", "At the mitral annulus", "At the LV apex"], correctIndex: 0, rationale: "Vena contracta (VC) is measured in the PLAX or A4C view at the narrowest point of the color jet immediately downstream of the orifice. Severe MR: VC ≥7 mm.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-239", stem: "Flow convergence color Doppler optimization for PISA requires:", options: ["Lowering the Nyquist limit (color baseline shift) toward the direction of flow to enlarge the hemisphere", "Increasing the Nyquist limit to maximum", "Turning off color Doppler", "Increasing depth to maximum"], correctIndex: 0, rationale: "Shifting the color baseline toward the flow direction (lowering the aliasing velocity) makes the PISA hemisphere larger and easier to measure. A hemisphere radius of 1.0 cm is ideal.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-240", stem: "For aortic regurgitation, the PISA method measures flow convergence on the:", options: ["Aortic side of the valve during diastole", "Ventricular side during systole", "Left atrial side during systole", "Pulmonary artery side"], correctIndex: 0, rationale: "AR PISA: the flow convergence zone is on the aortic side of the valve during diastole, as blood converges from the aorta through the regurgitant orifice into the LV.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-241", stem: "The continuity equation for valve area assumes:", options: ["No significant regurgitation at either measurement site and conservation of mass through the valve", "Turbulent flow at all sites", "Constant velocity throughout", "Equal chamber sizes"], correctIndex: 0, rationale: "The continuity equation assumes flow entering a region equals flow leaving it. Significant regurgitation at the measurement sites (LVOT or AV) introduces error by adding or subtracting volume.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Continuity Equation" },
  { id: "cardecho-242", stem: "In a low-flow, low-gradient severe AS with preserved LVEF (paradoxical low-flow), the SVI is:", options: ["<35 mL/m² despite normal or near-normal LVEF", ">50 mL/m² with high LVEF", "Normal (>35 mL/m²) with normal LVEF", "<20 mL/m² with severely reduced LVEF"], correctIndex: 0, rationale: "Paradoxical low-flow, low-gradient severe AS: LVEF ≥50%, SVI <35 mL/m², mean gradient <40 mmHg, AVA <1.0 cm². Often seen in elderly hypertensive patients with small LV cavity.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-243", stem: "During dobutamine stress echo for low-flow AS, true severe AS is confirmed when:", options: ["AVA remains <1.0 cm² with increased flow and gradient rises proportionally", "AVA increases to >1.5 cm² with increased flow", "Gradient remains unchanged despite increased flow", "Heart rate does not change"], correctIndex: 0, rationale: "True severe AS: dobutamine increases CO, gradient rises (mean gradient >40 mmHg), but AVA remains <1.0 cm² (fixed obstruction). Pseudo-severe: AVA increases >1.0 cm² with augmented flow.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-244", stem: "The simplified continuity equation using peak velocities instead of VTI calculates AVA as:", options: ["(LVOT area × LVOT peak velocity) / AV peak velocity", "(AV peak velocity)² / LVOT area", "LVOT VTI / AV peak velocity", "Peak velocity × heart rate"], correctIndex: 0, rationale: "AVA = (LVOT CSA × V_LVOT) / V_AV using peak velocities. This is a simplification assuming similar flow profile shapes. It may be less accurate than VTI-based calculations but is faster.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Continuity Equation" },
  { id: "cardecho-245", stem: "The effective orifice area (EOA) of a prosthetic valve is calculated using:", options: ["The continuity equation, comparing LVOT flow to transprosthetic flow", "Visual inspection alone", "Heart rate and blood pressure", "The Gorlin formula only"], correctIndex: 0, rationale: "Prosthetic valve EOA uses the continuity equation: EOA = (LVOT CSA × LVOT VTI) / Prosthetic VTI. Results are compared to published normal ranges for the specific prosthesis type and size.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-246", stem: "Patient-prosthesis mismatch occurs when:", options: ["The indexed EOA of the prosthetic valve is too small for the patient's body size, resulting in high residual gradients", "The prosthetic valve is too large", "There is paravalvular regurgitation", "The prosthesis is in normal position"], correctIndex: 0, rationale: "PPM: indexed EOA <0.85 cm²/m² (moderate) or <0.65 cm²/m² (severe) for aortic prostheses. Despite a normally functioning prosthesis, the valve is too small for the patient's hemodynamic needs.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-247", stem: "The pressure gradient across a normal bioprosthetic aortic valve is typically:", options: ["10-20 mmHg mean gradient, varying by valve size and type", "0 mmHg", "50-60 mmHg", ">80 mmHg"], correctIndex: 0, rationale: "Normal bioprosthetic AV gradients vary by type and size: generally mean gradient 10-20 mmHg. Each valve has published normal hemodynamic parameters. Higher gradients may indicate stenosis or PPM.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-248", stem: "Transprosthetic velocity and gradient are expected to be higher in:", options: ["Smaller prosthetic valve sizes due to smaller effective orifice area", "Larger prosthetic valves", "Bioprosthetic vs mechanical valves always", "Pulmonary position prostheses"], correctIndex: 0, rationale: "Smaller prostheses have smaller EOA, producing higher velocities and gradients at any given flow rate. Size 19 mm valves typically have higher normal gradients than size 25 mm valves.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-249", stem: "The Doppler index (DI) for prosthetic valves is defined as:", options: ["LVOT VTI / prosthetic valve VTI, with DI <0.25 suggesting significant obstruction", "Prosthetic VTI / LVOT VTI", "Peak velocity only", "Mean gradient / peak gradient"], correctIndex: 0, rationale: "DI = LVOT VTI / prosthetic VTI. It is analogous to DVI for native valves. DI <0.25 is suspicious for prosthetic valve obstruction. Serial comparison detects progressive stenosis.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-250", stem: "Localization of pressure gradients can be achieved with:", options: ["PW Doppler stepping from proximal to distal across the region of interest to identify where velocity increases", "CW Doppler alone", "2D imaging only", "M-mode echocardiography"], correctIndex: 0, rationale: "PW Doppler provides range resolution (depth-specific velocity). By systematically moving the sample volume from LVOT through the AV and beyond, the site of obstruction (subvalvular, valvular, supravalvular) is identified.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Bernoulli Equation" },
  { id: "cardecho-251", stem: "The time constant of LV relaxation (tau) reflects:", options: ["The rate of active relaxation during isovolumic relaxation, with prolonged tau indicating diastolic dysfunction", "Systolic ejection force", "Valve opening speed", "Heart rate"], correctIndex: 0, rationale: "Tau is the time constant of the exponential LV pressure decline during isovolumic relaxation. Prolonged tau indicates impaired active relaxation. It can be estimated non-invasively from IVRT and systolic BP.", difficulty: 5, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-252", stem: "The E/A ratio in a healthy 25-year-old is typically:", options: ["1.5-2.0 (E dominant, reflecting normal rapid early filling)", "0.5-0.7 (A dominant)", "3.0-4.0", "0.1-0.3"], correctIndex: 0, rationale: "Young adults have brisk LV relaxation, producing a tall E wave with E/A 1.5-2.0. With aging, relaxation slows, and E/A approaches 1.0 by age 60-70, with increasing A wave contribution.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-253", stem: "The PISA angle correction factor is applied when:", options: ["The flow convergence zone is constrained by adjacent structures, forming less than a full hemisphere", "The orifice is perfectly circular", "Flow is laminar", "Only for aortic regurgitation"], correctIndex: 0, rationale: "If the PISA forms a partial hemisphere due to wall constraint (e.g., the MV leaflet confines the zone), an angle correction (α/180°) adjusts the surface area calculation. The angle α is measured between the constraining surfaces.", difficulty: 5, category: "Hemodynamics & Calculations", topic: "PISA Method" },
  { id: "cardecho-254", stem: "Right ventricular systolic pressure (RVSP) equals PASP when:", options: ["There is no pulmonic stenosis (no RV outflow obstruction)", "Pulmonic stenosis is present", "TR is absent", "ASD is present"], correctIndex: 0, rationale: "RVSP = PASP only in the absence of RVOT or pulmonic valve obstruction. With PS, RVSP > PASP. RVSP is derived from the TR jet: RVSP = 4(V_TR)² + RAP.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-255", stem: "The LA pressure can be estimated from:", options: ["Pulmonary artery diastolic pressure when there is no pulmonary vascular disease (PADP ≈ PCWP ≈ LAP)", "TR jet velocity alone", "LVOT VTI", "Aortic root dimension"], correctIndex: 0, rationale: "In the absence of significant pulmonary vascular disease, PADP approximates PCWP which approximates mean LAP. PADP = 4(end-diastolic PR velocity)² + RAP.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
  { id: "cardecho-256", stem: "For accurate Doppler measurements, the angle of incidence between the ultrasound beam and blood flow should be:", options: ["Less than 20 degrees (ideally 0 degrees, parallel)", "90 degrees (perpendicular)", "45 degrees", "Any angle is acceptable"], correctIndex: 0, rationale: "Doppler velocity is accurate only when the beam is parallel to flow (cos 0° = 1). At 20°, velocity is underestimated by ~6% (cos 20° = 0.94). At 60°, underestimation is 50%.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "Bernoulli Equation" },
  { id: "cardecho-257", stem: "Angle correction in spectral Doppler:", options: ["Should NOT be applied in echocardiography because the exact flow direction is unknown in 3D space", "Should always be used to correct for beam angle", "Is mandatory for all measurements", "Only applies to color Doppler"], correctIndex: 0, rationale: "Unlike vascular ultrasound, angle correction is not applied in cardiac Doppler because the flow direction is complex and 3D. Instead, the operator aligns the beam as parallel to flow as possible.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Bernoulli Equation" },
  { id: "cardecho-258", stem: "The peak E velocity of mitral inflow is normally:", options: ["0.6-1.0 m/s", "2.0-3.0 m/s", "0.1-0.2 m/s", "4.0-5.0 m/s"], correctIndex: 0, rationale: "Normal mitral inflow E velocity is 0.6-1.0 m/s, measured by PW Doppler at the leaflet tips. E velocity >1.5 m/s in MS suggests significant stenosis. E velocity is influenced by LA pressure and LV relaxation.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-259", stem: "The mitral inflow A wave velocity reflects:", options: ["Late diastolic filling due to left atrial contraction", "Early passive filling", "Systolic ejection", "Isovolumic relaxation"], correctIndex: 0, rationale: "The A wave represents late diastolic filling from atrial contraction. Normal A velocity: 0.4-0.7 m/s. Increased A wave with reduced E wave (E/A <0.8) indicates impaired relaxation.", difficulty: 1, category: "Hemodynamics & Calculations", topic: "E/e' Ratio" },
  { id: "cardecho-260", stem: "In high cardiac output states (anemia, thyrotoxicosis), Doppler gradients across normal valves may:", options: ["Be elevated due to increased flow velocity, mimicking stenosis", "Be decreased below normal", "Remain completely unchanged", "Become unmeasurable"], correctIndex: 0, rationale: "High CO increases transvalvular flow velocity, raising Doppler-derived gradients even with normal valve areas. Clinical context and valve area (not gradient alone) should be used to assess severity.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Bernoulli Equation" },
  { id: "cardecho-261", stem: "The Doppler half-time method for prosthetic mitral valves:", options: ["May be inaccurate because prosthetic valves have intrinsic flow obstruction affecting PHT", "Is always accurate for any prosthesis", "Should replace all other methods", "Gives identical results to native valve PHT"], correctIndex: 0, rationale: "PHT for prosthetic MV is unreliable as a standalone measure because different prostheses have inherent flow characteristics. Serial comparison of the same valve's parameters is more useful than absolute values.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Pressure Half-Time" },
  { id: "cardecho-262", stem: "Effective forward stroke volume in aortic regurgitation is:", options: ["Total LV stroke volume minus regurgitant volume", "Total LV stroke volume plus regurgitant volume", "LVOT VTI × aortic root area", "Only the volume that regurgitates"], correctIndex: 0, rationale: "Forward SV = Total SV - Regurgitant Volume. In AR, the LV ejects a large total SV but some returns through the incompetent valve. Only the forward SV contributes to systemic perfusion.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-263", stem: "The RVOT diameter for Qp calculation is measured at:", options: ["The RVOT just proximal to the pulmonic valve in the PSAX view", "The LVOT in PLAX", "The mitral annulus", "The IVC"], correctIndex: 0, rationale: "RVOT diameter is measured in the PSAX at the aortic valve level, just proximal to the pulmonic valve. RVOT CSA = π(d/2)². RVOT VTI is obtained by PW Doppler at the same level.", difficulty: 2, category: "Hemodynamics & Calculations", topic: "Qp/Qs" },
  { id: "cardecho-264", stem: "In the presence of significant aortic regurgitation, Qp/Qs calculation using LVOT flow:", options: ["Overestimates Qs because LVOT flow includes both forward and regurgitant volumes", "Underestimates Qs", "Is not affected", "Gives accurate results"], correctIndex: 0, rationale: "With significant AR, LVOT SV includes both forward flow and the volume that will regurgitate. This overestimates systemic flow (Qs), making Qp/Qs appear lower than actual and potentially underestimating shunt significance.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Qp/Qs" },
  { id: "cardecho-265", stem: "LV mass is calculated from M-mode or 2D measurements using:", options: ["The ASE-recommended formula based on LVIDd, IVSd, and LVPWd, assuming a truncated ellipsoid model", "LVOT VTI only", "E/e' ratio", "TR velocity"], correctIndex: 0, rationale: "LV mass (ASE) = 0.8 × {1.04 × [(IVSd + LVIDd + LVPWd)³ - LVIDd³]} + 0.6 g. Indexed to BSA: normal LV mass index <95 g/m² (women), <115 g/m² (men). Elevated values indicate LVH.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-266", stem: "Relative wall thickness (RWT) is calculated as:", options: ["(2 × LVPWd) / LVIDd", "IVSd / LVPWd", "LVEF × heart rate", "LV mass / BSA"], correctIndex: 0, rationale: "RWT = (2 × LVPWd) / LVIDd. RWT >0.42 = concentric geometry. Combined with LV mass: normal geometry (normal mass, normal RWT), concentric remodeling (normal mass, high RWT), concentric hypertrophy (high mass, high RWT), eccentric hypertrophy (high mass, normal RWT).", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Stroke Volume" },
  { id: "cardecho-267", stem: "The myocardial performance index (MPI/Tei index) for the right ventricle is measured by:", options: ["(IVCT + IVRT) / ET using the tricuspid annular TDI signal or comparing TR duration to RVOT ejection time", "LVOT VTI / heart rate", "Mitral E/A ratio", "TAPSE only"], correctIndex: 0, rationale: "RV Tei index can be measured by TDI at the lateral tricuspid annulus: (IVCT + IVRT)/ET. Normal RV Tei <0.40 (PW) or <0.55 (TDI). Increased values indicate RV global dysfunction.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Cardiac Output" },
  { id: "cardecho-268", stem: "The velocity ratio across a prosthetic aortic valve should be monitored over time because:", options: ["An increasing ratio (prosthetic VTI/LVOT VTI) suggests progressive prosthetic valve obstruction or stenosis", "It should decrease with time", "It has no clinical significance", "Only baseline values matter"], correctIndex: 0, rationale: "Serial monitoring of the velocity ratio (or DI) detects prosthetic valve dysfunction. A DI decrease >0.10 from baseline or prosthetic velocity increase >0.5 m/s/year suggests developing obstruction.", difficulty: 3, category: "Hemodynamics & Calculations", topic: "Valve Area Calculations" },
  { id: "cardecho-269", stem: "In severe tricuspid regurgitation, the CW Doppler TR jet may show:", options: ["A dense, triangular signal with an early peak and rapid decline (cutoff sign) due to rapid RV-RA pressure equalization", "A complete absence of signal", "A very high velocity (>5 m/s) signal", "A late-peaking symmetric signal"], correctIndex: 0, rationale: "Severe TR produces a dense TR signal that peaks early and shows rapid decline (V-wave cutoff sign) because the massive regurgitant volume rapidly equalizes RV and RA pressures. The peak velocity may be paradoxically low.", difficulty: 4, category: "Hemodynamics & Calculations", topic: "Pulmonary Pressures" },
];
